import{_ as t,o as s,c as i,a6 as o}from"./chunks/framework.wLlb4ebq.js";const u=JSON.parse('{"title":"Extension Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"extension/permissions.md","filePath":"extension/permissions.md"}'),a={name:"extension/permissions.md"};function n(r,e,d,l,c,h){return s(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="extension-permissions" tabindex="-1">Extension Permissions <a class="header-anchor" href="#extension-permissions" aria-label="Permalink to “Extension Permissions”">​</a></h1><p>扩展权限应被理解为能力声明，而不是权限清单。每个权限都应该能映射到用户可见功能。</p><h2 id="feature-to-permission-table" tabindex="-1">feature-to-permission table <a class="header-anchor" href="#feature-to-permission-table" aria-label="Permalink to “feature-to-permission table”">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Permission / host access</th><th>Why it is needed</th></tr></thead><tbody><tr><td>浏览器书签导入</td><td><code>bookmarks</code></td><td>读取用户书签树和文件夹路径</td></tr><tr><td>Notion 写入</td><td><code>api.notion.com</code> host access</td><td>创建页面、更新属性、读取工作区列表</td></tr><tr><td>GitHub 导入</td><td><code>api.github.com</code> host access</td><td>读取 Stars、Repos、Forks、Gists</td></tr><tr><td>AI 助手</td><td>AI provider host access</td><td>调用 OpenAI、Anthropic、Gemini 或自定义端点</td></tr><tr><td>通用网页剪藏</td><td>host page access</td><td>读取当前页面标题、摘要和 DOM 线索</td></tr><tr><td>本地配置与保险箱</td><td>extension storage / GM storage</td><td>保存非敏感配置，以及敏感凭证的加密保险箱 payload</td></tr></tbody></table><h2 id="required-vs-optional" tabindex="-1">Required vs optional <a class="header-anchor" href="#required-vs-optional" aria-label="Permalink to “Required vs optional”">​</a></h2><p>当前仓库有两条扩展交付链，权限边界需要分开理解：</p><ul><li><code>chrome-extension/manifest.json</code> 是书签桥接扩展，只声明 <code>bookmarks</code> 权限，并在所有 <code>http/https</code> 页面注入 content script。</li><li>书签桥接扩展虽然注入范围较宽，但运行时只有在页面上存在活动中的 LD-Notion 根节点时，才会响应书签桥接请求。</li><li><code>scripts/build-extension.js</code> 生成的 <code>chrome-extension-full/</code> 默认使用 <code>bounded_hosts</code> profile：跨域网络 <code>host_permissions</code> 只覆盖 Linux.do、Notion API、GitHub API、AI provider 与必要的 AWS 资源。</li><li>为了保持与 userscript 一致的 GitHub / Zhihu / 通用网页入口，<code>chrome-extension-full/</code> 的 <code>content_scripts.matches</code> 仍覆盖这些页面，并通过 <code>exclude_matches</code> 排除搜索引擎、邮箱与本地开发地址。</li><li>如果未来进入浏览器商店分发，应继续评估 optional permissions，以进一步降低初始信任成本。</li></ul><h2 id="trust-boundaries" tabindex="-1">Trust boundaries <a class="header-anchor" href="#trust-boundaries" aria-label="Permalink to “Trust boundaries”">​</a></h2><div class="language-mermaid"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  User[User consent] --&gt; Manifest[Manifest permissions]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Manifest --&gt; Runtime[Runtime checks]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Runtime --&gt; Guard[OperationGuard]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Guard --&gt; Audit[Audit log]</span></span></code></pre></div><h2 id="contract" tabindex="-1">Contract <a class="header-anchor" href="#contract" aria-label="Permalink to “Contract”">​</a></h2><ul><li>Permissions SHOULD map to documented features。</li><li>Secrets MUST NOT be written into DOM。</li><li>Dangerous Notion writes MUST still pass OperationGuard, even if extension permissions allow network access。</li><li>The bookmark-bridge extension MUST reject bridge requests outside an active LD-Notion panel context。</li><li><code>bounded_hosts</code> SHOULD remain the default release profile for <code>chrome-extension-full</code> unless a narrower production profile replaces it。</li></ul>`,11)])])}const m=t(a,[["render",n]]);export{u as __pageData,m as default};
